// Merge webhook body with job row. If no job found, output error. Strict required-column check (Fix #5).
const REQUIRED_COLUMNS = ['bookingUid','cleanerId','status','checkoutTimeUTC','scheduledCleaningTimeUTC','calendarEventId','clockInTimeUTC'];
const webhook = $('Webhook').first().json;
const body = webhook.body || webhook;
const items = $input.all();
if (!items.length || !(items[0].json?.bookingUid || items[0].json?.bookinguid)) {
  return [{ json: { _error: 'Invalid booking', _code: 400 } }];
}
const job = items[0].json;
for (const col of REQUIRED_COLUMNS) {
  if (job[col] === undefined || job[col] === null)
    return [{ json: { _error: 'Missing required column configuration', _code: 500 } }];
}
return [{ json: { ...job, assignedCleanerId: (job.cleanerId ?? '').toString().trim(), ...body, bookingUid: job.bookingUid || body.bookingUid, cleanerId: (body.cleanerId ?? job.cleanerId ?? '').toString().trim(), gpsLat: body.gpsLat, gpsLng: body.gpsLng } }];

// STEP 2 – Validations. All must pass. Checkout uses ONLY checkoutTimeUTC (Fix #1).
const j = $input.first().json;
const incomingCleanerId = (j.cleanerId ?? '').toString().trim();
const assignedCleanerId = (j.assignedCleanerId ?? j.cleanerId ?? '').toString().trim();
const status = (j.status ?? '').toString().trim();
const clockInTimeUTC = (j.clockInTimeUTC ?? '').toString().trim();
const calendarEventId = (j.calendarEventId ?? '').toString().trim();
const now = new Date();
const checkoutTimeUTC = j.checkoutTimeUTC;
const checkoutTime = checkoutTimeUTC != null ? new Date(checkoutTimeUTC) : null;

if (incomingCleanerId !== assignedCleanerId)
  return [{ json: { ...j, _error: 'Cleaner does not match assigned cleaner', _code: 400 } }];
if (status !== 'ASSIGNED')
  return [{ json: { ...j, _error: 'Job status is not ASSIGNED', _code: 400 } }];
if (clockInTimeUTC !== '')
  return [{ json: { ...j, _error: 'Already clocked in', _code: 400 } }];
if (!calendarEventId)
  return [{ json: { ...j, _error: 'No calendar event for this job', _code: 400 } }];
if (checkoutTime == null || isNaN(checkoutTime.getTime()))
  return [{ json: { ...j, _error: 'Clock-in not allowed before checkout time', _code: 400 } }];
if (now < checkoutTime)
  return [{ json: { ...j, _error: 'Clock-in not allowed before checkout time', _code: 400 } }];

return [{ json: { ...j } }];

// STEP 3 – Haversine distance (meters) and gpsStatus. Strict type safety for GPS (Fix #4).
const item = $input.first().json;
const job = $('Validations').first().json;
const lat1 = Number(job.gpsLat);
const lon1 = Number(job.gpsLng);
if (Number.isNaN(lat1) || Number.isNaN(lon1))
  return [{ json: { ...job, _error: 'Invalid GPS coordinates', _code: 400 } }];
const getNum = (v) => (v !== undefined && v !== null && v !== '') ? Number(v) : NaN;
const lat2 = getNum(item.propertyLat ?? item.latitude ?? item.propertyLatitude);
const lon2 = getNum(item.propertyLng ?? item.longitude ?? item.propertyLongitude);

function haversineMeters(lat1, lon1, lat2, lon2) {
  const R = 6371000;
  const dLat = (lat2 - lat1) * Math.PI / 180;
  const dLon = (lon2 - lon1) * Math.PI / 180;
  const a = Math.sin(dLat/2)**2 + Math.cos(lat1*Math.PI/180)*Math.cos(lat2*Math.PI/180)*Math.sin(dLon/2)**2;
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return R * c;
}

const distance = (Number.isFinite(lat1) && Number.isFinite(lon1) && Number.isFinite(lat2) && Number.isFinite(lon2))
  ? haversineMeters(lat1, lon1, lat2, lon2)
  : null;
const gpsStatus = (distance !== null && distance <= 100) ? 'INSIDE_RADIUS' : 'OUTSIDE_RADIUS';
return [{ json: { ...job, distance, gpsStatus } }];

// STEP 4 – Late check. Use ONLY scheduledCleaningTimeUTC. All comparisons UTC-only.
const item = $input.first().json;
const scheduledCleaningTimeUTC = item.scheduledCleaningTimeUTC;
const serverTime = new Date();
const clockInTimeUTC = serverTime.toISOString();
const deadline = scheduledCleaningTimeUTC != null && scheduledCleaningTimeUTC !== '' ? new Date(scheduledCleaningTimeUTC) : null;
if (deadline != null && !isNaN(deadline.getTime())) {
  deadline.setUTCHours(deadline.getUTCHours() + 1);
}
const lateFlag = deadline != null && !isNaN(deadline.getTime()) && serverTime > deadline;
return [{ json: { ...item, lateFlag, clockInTimeUTC } }];

