// Fix #3 – Race condition: abort if clockInTimeUTC already set.
const reFetched = $input.first().json;
const preUpdate = $('Late Check').first().json;
const existing = (reFetched.clockInTimeUTC ?? '').toString().trim();
if (existing !== '')
  return [{ json: { _error: 'Clock-in already recorded', _code: 409 } }];
return [{ json: { ...preUpdate } }];
